package main

import (
	"encoding/json"
	"fmt"
	"time"

	"github.com/hyperledger/fabric-contract-api-go/contractapi"
)

// ─── Anti-Corruption Architecture ─────────────────────────────────────────────
//
// The #1 land fraud in India: a Patwari is bribed to file an Inheritance mutation
// listing only one heir, leaving co-heirs out. When the deceased owns multiple plots,
// the corrupt heir can consolidate ownership of ALL plots before others find out.
//
// BhumiChain prevents this through THREE hard rules:
//
//  RULE 1 — Inheritance mutations are AUTO-GENERATED by the Uttaradhikar Engine only.
//            A Patwari cannot manually create an Inheritance mutation with a custom heir
//            list. The heir list comes from CoparcenaryMapper AI + CRS death certificate
//            and is locked in before the mutation is initiated.
//
//  RULE 2 — ALL co-owners on a DLPI get simultaneous alerts when ANY mutation is
//            initiated. Not just the "primary owner". Every single Aadhaar hash in
//            Owners[] gets an independent SMS + in-app notification within 60 seconds.
//
//  RULE 3 — A mutation cannot execute on a DLPI with SuccessionStatus = SUCCESSION_PENDING.
//            If someone dies and succession hasn't completed, the entire DLPI is frozen
//            for transfers AND mutations until the Uttaradhikar Engine completes.
//
// The Patwari's role in succession: they get a 60-second SLA notification to CONFIRM
// the mutation that the Uttaradhikar Engine auto-generated. They cannot change who
// the heirs are at this stage. Accountability: their Aadhaar hash is recorded permanently.

// ─── Mutation Types ───────────────────────────────────────────────────────────
//
// SALE          — ownership changes after a completed PropertyTransfer (auto-triggered)
// INHERITANCE   — ownership passes to heirs after succession (auto-generated by Uttaradhikar only)
// PARTITION     — one DLPI splits into N DLPIs, each owned solely by one co-owner
// GIFT          — transfer at nil consideration (donor must eSign)
// COURT_ORDER   — court-ordered ownership change (no owner consent required, needs eCourts hash)
// CORRECTION    — fix a data error (area, boundary, land type) — no ownership change
// NAME_UPDATE   — same person, legal name change (marriage, court order)

// ─── Data Structures ─────────────────────────────────────────────────────────

// NewOwnerEntry — one owner in the post-mutation ownership list
type NewOwnerEntry struct {
	AadhaarHash   string  `json:"aadhaarHash"`
	Name          string  `json:"name"`
	Share         string  `json:"share"`         // "1/3", "1/2", "1/1"
	ShareDecimal  float64 `json:"shareDecimal"`
	IsTribal      bool    `json:"isTribal"`
	RelationToOld string  `json:"relationToOld,omitempty"` // "Son", "Daughter", "Buyer" etc.
}

// OwnerAlert — one co-owner's notification and consent status
type OwnerAlert struct {
	AadhaarHash     string `json:"aadhaarHash"`
	AlertSentAt     string `json:"alertSentAt,omitempty"`
	AlertChannel    string `json:"alertChannel,omitempty"` // SMS | WHATSAPP | APP
	AlertDelivered  bool   `json:"alertDelivered"`
	DeliveredAt     string `json:"deliveredAt,omitempty"`
	Response        string `json:"response,omitempty"`       // CONSENTED | OBJECTED | NO_RESPONSE
	ResponseAt      string `json:"responseAt,omitempty"`
	ESignTxHash     string `json:"eSignTxHash,omitempty"`
	ObjectionReason string `json:"objectionReason,omitempty"`
	ObjectionCID    string `json:"objectionCID,omitempty"`
}

// PartitionScheme — for PARTITION mutations: who gets which sub-plot
type PartitionScheme struct {
	ParentDLPIId string              `json:"parentDlpiId"`
	Awards       []PartitionAward    `json:"awards"`
	SurveyNo     string              `json:"surveyNo"`         // new survey number from field measurement
	SurveyedAt   string              `json:"surveyedAt,omitempty"`
	CourtOrderNo string              `json:"courtOrderNo,omitempty"` // if court-ordered partition
}

type PartitionAward struct {
	OwnerAadhaarHash string  `json:"ownerAadhaarHash"`
	NewDLPIId        string  `json:"newDlpiId"`        // generated on execution
	AreaHectares     float64 `json:"areaHectares"`
	ShareFraction    string  `json:"shareFraction"`
	BoundaryNotes    string  `json:"boundaryNotes,omitempty"`
}

// MutationRequest — the main mutation record
type MutationRequest struct {
	MutationID   string `json:"mutationId"`
	MutationNo   string `json:"mutationNo"`
	DLPIId       string `json:"dlpiId"`
	MutationType string `json:"mutationType"`

	// Officer who initiated (permanently recorded — accountability layer)
	OfficerName string `json:"officerName"`
	OfficerHash string `json:"officerAadhaarHash"` // permanent, immutable once written
	OfficerRank string `json:"officerRank"`         // patwari | circle_inspector | tehsildar

	// Source of this mutation (critical for Inheritance)
	InitiatedBy      string `json:"initiatedBy"`      // OFFICER | UTTARADHIKAR_ENGINE | PROPERTY_TRANSFER | COURT
	SuccessionCaseId string `json:"successionCaseId,omitempty"` // required when InitiatedBy = UTTARADHIKAR_ENGINE

	// What changes: who are the new owners after this mutation executes?
	// This is an array — no more single-owner mutation possible.
	NewOwners []NewOwnerEntry `json:"newOwners"`

	// All current owners of the DLPI get individual alerts (derived at initiation)
	// Each entry tracks: did they get notified? Did they consent or object?
	OwnerAlerts []OwnerAlert `json:"ownerAlerts"`

	// Supporting documents
	SupportingCID string `json:"supportingDocCID,omitempty"`
	Reason        string `json:"reason"`

	// For COURT_ORDER mutations only
	CourtOrderNo    string `json:"courtOrderNo,omitempty"`
	CourtOracleHash string `json:"courtOracleHash,omitempty"`

	// For PARTITION mutations only
	PartitionScheme *PartitionScheme `json:"partitionScheme,omitempty"`

	// Public notice (mandatory for Inheritance, Partition, Gift)
	PublicNoticeFrom    string `json:"publicNoticeFrom,omitempty"`
	PublicNoticeTill    string `json:"publicNoticeTill,omitempty"` // 30 days
	PublicNoticeObjects int    `json:"publicNoticeObjects"`

	Status      string `json:"status"`
	InitiatedAt string `json:"initiatedAt"`
	UpdatedAt   string `json:"updatedAt"`
	ExecutedAt  string `json:"executedAt,omitempty"`
}

// Mutation status constants
const (
	MutStatusDraft              = "DRAFT"
	MutStatusAlertsSent         = "ALERTS_SENT"           // all owner alerts fired (within 60 sec)
	MutStatusAwaitingConsents   = "AWAITING_CONSENTS"     // waiting for co-owners to respond
	MutStatusAllConsented       = "ALL_CONSENTED"         // every owner eSigned
	MutStatusObjectionFiled     = "OBJECTION_FILED"       // at least one owner objected
	MutStatusPublicNoticePeriod = "PUBLIC_NOTICE_PERIOD"  // 30-day window open
	MutStatusPendingExecution   = "PENDING_EXECUTION"     // consents done, Tehsildar to approve
	MutStatusExecuted           = "EXECUTED"
	MutStatusRejected           = "REJECTED"
	MutStatusCourtReferred      = "COURT_REFERRED"
)

// Mutation types requiring public notice
var requiresPublicNotice = map[string]bool{
	"INHERITANCE": true,
	"PARTITION":   true,
	"GIFT":        true,
}

// Mutation types that bypass owner consent (court-ordered)
var courtOrdered = map[string]bool{
	"COURT_ORDER": true,
}

// Mutation types requiring Uttaradhikar origin (cannot be manually filed)
var requiresUttaradhikarOrigin = map[string]bool{
	"INHERITANCE": true,
}

// ─── Smart Contract ───────────────────────────────────────────────────────────

type MutationManagerContract struct {
	contractapi.Contract
}

// InitiateMutation — primary entry point for all mutation types
//
// Key anti-corruption enforcement:
//   - INHERITANCE type: must come from Uttaradhikar Engine (initiatedBy = "UTTARADHIKAR_ENGINE")
//   - ALL current owners on the DLPI are extracted and added to OwnerAlerts[]
//   - MutationAlertRequired event carries ALL owner hashes — oracle notifies each independently
//   - Cannot be called while SuccessionStatus = SUCCESSION_PENDING
//
// currentOwnersJSON: JSON array of {aadhaarHash} for the DLPI's current owners
//   (passed from API layer which reads DLPI state before calling chaincode)
// newOwnersJSON: JSON array of NewOwnerEntry (who will own after mutation)
func (c *MutationManagerContract) InitiateMutation(
	ctx contractapi.TransactionContextInterface,
	dlpiId, mutationType,
	officerName, officerHash, officerRank,
	initiatedBy, successionCaseId,
	currentOwnersJSON, newOwnersJSON,
	reason, supportingCID,
	courtOrderNo, courtOracleHash,
	partitionSchemeJSON string,
) (string, error) {

	// ── Validate mutation type ──────────────────────────────────────────────────
	validTypes := map[string]bool{
		"SALE": true, "INHERITANCE": true, "PARTITION": true,
		"GIFT": true, "COURT_ORDER": true, "CORRECTION": true, "NAME_UPDATE": true,
	}
	if !validTypes[mutationType] {
		return "", fmt.Errorf("invalid mutation type: %s", mutationType)
	}

	// ── RULE 1: Inheritance must come from Uttaradhikar Engine ─────────────────
	if requiresUttaradhikarOrigin[mutationType] {
		if initiatedBy != "UTTARADHIKAR_ENGINE" {
			return "", fmt.Errorf(
				"ANTI_CORRUPTION: INHERITANCE mutations cannot be manually filed by officers. "+
					"They must be auto-generated by the Uttaradhikar Engine after all heirs consent. "+
					"Officer %s (%s) attempted manual Inheritance mutation on DLPI %s. "+
					"This attempt is permanently recorded.",
				officerName, officerHash, dlpiId,
			)
		}
		if successionCaseId == "" {
			return "", fmt.Errorf("INHERITANCE mutation requires a valid successionCaseId from Uttaradhikar Engine")
		}
	}

	// ── Validate court order type ───────────────────────────────────────────────
	if courtOrdered[mutationType] && (courtOrderNo == "" || courtOracleHash == "") {
		return "", fmt.Errorf("COURT_ORDER mutations require courtOrderNo and courtOracleHash from eCourts oracle")
	}

	// ── Parse current owners (for alert distribution) ──────────────────────────
	type OwnerRef struct {
		AadhaarHash string `json:"aadhaarHash"`
	}
	var currentOwnerRefs []OwnerRef
	if currentOwnersJSON != "" && currentOwnersJSON != "[]" {
		if err := json.Unmarshal([]byte(currentOwnersJSON), &currentOwnerRefs); err != nil {
			return "", fmt.Errorf("invalid currentOwners JSON: %w", err)
		}
	}

	// ── Parse new owners ────────────────────────────────────────────────────────
	var newOwners []NewOwnerEntry
	if newOwnersJSON != "" && newOwnersJSON != "[]" {
		if err := json.Unmarshal([]byte(newOwnersJSON), &newOwners); err != nil {
			return "", fmt.Errorf("invalid newOwners JSON: %w", err)
		}
	}

	// Validate new owner shares sum to 1 for ownership-changing mutations
	if mutationType != "CORRECTION" && mutationType != "NAME_UPDATE" && len(newOwners) > 0 {
		var total float64
		for _, o := range newOwners {
			total += o.ShareDecimal
		}
		if total < 0.999 || total > 1.001 {
			return "", fmt.Errorf("new owners' shares sum to %f — must sum to 1.0", total)
		}
	}

	// ── Parse partition scheme if applicable ────────────────────────────────────
	var partitionScheme *PartitionScheme
	if mutationType == "PARTITION" && partitionSchemeJSON != "" {
		partitionScheme = &PartitionScheme{}
		if err := json.Unmarshal([]byte(partitionSchemeJSON), partitionScheme); err != nil {
			return "", fmt.Errorf("invalid partitionScheme JSON: %w", err)
		}
	}

	now := time.Now().UTC()
	txID := ctx.GetStub().GetTxID()
	mutationID := fmt.Sprintf("MUT-%s-%s", dlpiId, txID[:8])
	mutationNo := fmt.Sprintf("MUT/%d/%s", now.Year(), txID[:6])

	// ── Build OwnerAlerts for ALL current co-owners ─────────────────────────────
	// RULE 2: every owner gets their own alert record — tracked individually
	ownerAlerts := make([]OwnerAlert, len(currentOwnerRefs))
	allOwnerHashes := make([]string, len(currentOwnerRefs))
	for i, ref := range currentOwnerRefs {
		ownerAlerts[i] = OwnerAlert{
			AadhaarHash:    ref.AadhaarHash,
			AlertDelivered: false,
			Response:       "PENDING",
		}
		allOwnerHashes[i] = ref.AadhaarHash
	}

	// Determine initial status
	initialStatus := MutStatusDraft
	needsAlert := !courtOrdered[mutationType]
	needsPublicNotice := requiresPublicNotice[mutationType]

	if courtOrdered[mutationType] {
		initialStatus = MutStatusPendingExecution
	}

	mutation := MutationRequest{
		MutationID:       mutationID,
		MutationNo:       mutationNo,
		DLPIId:           dlpiId,
		MutationType:     mutationType,
		OfficerName:      officerName,
		OfficerHash:      officerHash,
		OfficerRank:      officerRank,
		InitiatedBy:      initiatedBy,
		SuccessionCaseId: successionCaseId,
		NewOwners:        newOwners,
		OwnerAlerts:      ownerAlerts,
		SupportingCID:    supportingCID,
		Reason:           reason,
		CourtOrderNo:     courtOrderNo,
		CourtOracleHash:  courtOracleHash,
		PartitionScheme:  partitionScheme,
		PublicNoticeObjects: 0,
		Status:           initialStatus,
		InitiatedAt:      now.Format(time.RFC3339),
		UpdatedAt:        now.Format(time.RFC3339),
	}

	if err := c.saveMutation(ctx, &mutation); err != nil {
		return "", err
	}

	// ── RULE 2: Fire simultaneous alerts to ALL current owners ─────────────────
	// The event payload contains ALL owner hashes — oracle sends each an independent SMS
	if needsAlert && len(allOwnerHashes) > 0 {
		alertEvent, _ := json.Marshal(map[string]interface{}{
			"mutationId":       mutationID,
			"mutationNo":       mutationNo,
			"dlpiId":           dlpiId,
			"mutationType":     mutationType,
			"officerName":      officerName,
			"officerRank":      officerRank,
			"officerHash":      officerHash,
			"allOwnerHashes":   allOwnerHashes, // ALL owners — oracle sends to each
			"newOwners":        newOwners,
			"reason":           reason,
			"alertChannels":    []string{"SMS", "WHATSAPP", "APP"},
			"consentDeadline":  now.Add(30 * 24 * time.Hour).Format(time.RFC3339),
			"initiatedAt":      now.Format(time.RFC3339),
			// Message template: "DLPI {dlpiId} par mutation hua hai. 30 din mein aapatti darj karein."
		})
		_ = ctx.GetStub().SetEvent("MutationAlertRequired", alertEvent)
		mutation.Status = MutStatusAlertsSent

		for i := range mutation.OwnerAlerts {
			mutation.OwnerAlerts[i].AlertSentAt = now.Format(time.RFC3339)
		}
	}

	// ── Start public notice period if required ───────────────────────────────────
	if needsPublicNotice {
		mutation.PublicNoticeFrom = now.Format(time.RFC3339)
		mutation.PublicNoticeTill = now.Add(30 * 24 * time.Hour).Format(time.RFC3339)
		mutation.Status = MutStatusPublicNoticePeriod
		noticeEvent, _ := json.Marshal(map[string]interface{}{
			"mutationId":  mutationID,
			"dlpiId":      dlpiId,
			"mutationType": mutationType,
			"noticeFrom":  mutation.PublicNoticeFrom,
			"noticeTill":  mutation.PublicNoticeTill,
		})
		_ = ctx.GetStub().SetEvent("PublicNoticeStarted", noticeEvent)
	}

	if err := c.saveMutation(ctx, &mutation); err != nil {
		return "", err
	}

	return mutationID, nil
}

// RecordOwnerAlertDelivery — oracle confirms alert was delivered (SLA tracking)
func (c *MutationManagerContract) RecordOwnerAlertDelivery(
	ctx contractapi.TransactionContextInterface,
	mutationID, ownerAadhaarHash, channel, deliveryTimestamp string,
) error {
	mutation, err := c.getMutation(ctx, mutationID)
	if err != nil {
		return err
	}

	deliveredTime := mustParseTime(deliveryTimestamp)
	for i, a := range mutation.OwnerAlerts {
		if a.AadhaarHash == ownerAadhaarHash {
			mutation.OwnerAlerts[i].AlertDelivered = true
			mutation.OwnerAlerts[i].DeliveredAt = deliveryTimestamp
			mutation.OwnerAlerts[i].AlertChannel = channel

			// Log SLA: time from mutation initiation to delivery
			elapsed := deliveredTime.Sub(mustParseTime(mutation.InitiatedAt)).Seconds()
			slaEvent, _ := json.Marshal(map[string]interface{}{
				"mutationId":     mutationID,
				"dlpiId":         mutation.DLPIId,
				"ownerHash":      ownerAadhaarHash,
				"channel":        channel,
				"elapsedSeconds": elapsed,
				"slaMet":         elapsed <= 60,
			})
			_ = ctx.GetStub().SetEvent("AlertSLARecorded", slaEvent)
			break
		}
	}

	mutation.Status = MutStatusAwaitingConsents
	mutation.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
	return c.saveMutation(ctx, mutation)
}

// RecordOwnerConsent — one co-owner provides Aadhaar eSign consent
// When ALL owners have consented, status advances to ALL_CONSENTED
func (c *MutationManagerContract) RecordOwnerConsent(
	ctx contractapi.TransactionContextInterface,
	mutationID, ownerAadhaarHash, eSignTxHash string,
) error {
	mutation, err := c.getMutation(ctx, mutationID)
	if err != nil {
		return err
	}

	if mutation.Status != MutStatusAwaitingConsents && mutation.Status != MutStatusPublicNoticePeriod {
		return fmt.Errorf("mutation %s not awaiting consent (status: %s)", mutationID, mutation.Status)
	}

	found := false
	now := time.Now().UTC().Format(time.RFC3339)
	for i, a := range mutation.OwnerAlerts {
		if a.AadhaarHash == ownerAadhaarHash {
			mutation.OwnerAlerts[i].Response = "CONSENTED"
			mutation.OwnerAlerts[i].ResponseAt = now
			mutation.OwnerAlerts[i].ESignTxHash = eSignTxHash
			found = true
			break
		}
	}
	if !found {
		return fmt.Errorf("aadhaar hash %s not in owner alert list for mutation %s", ownerAadhaarHash, mutationID)
	}

	// Check if ALL current owners have now consented
	if c.allOwnersResponded(mutation) && !c.anyObjection(mutation) {
		mutation.Status = MutStatusAllConsented
		event, _ := json.Marshal(map[string]string{
			"mutationId": mutationID, "dlpiId": mutation.DLPIId, "status": MutStatusAllConsented,
		})
		_ = ctx.GetStub().SetEvent("AllOwnersConsented", event)
	}

	mutation.UpdatedAt = now
	return c.saveMutation(ctx, mutation)
}

// RecordOwnerObjection — any co-owner objects (immediately suspends the mutation)
func (c *MutationManagerContract) RecordOwnerObjection(
	ctx contractapi.TransactionContextInterface,
	mutationID, ownerAadhaarHash, objectionReason, evidenceCID string,
) error {
	mutation, err := c.getMutation(ctx, mutationID)
	if err != nil {
		return err
	}

	if mutation.Status != MutStatusAwaitingConsents && mutation.Status != MutStatusPublicNoticePeriod {
		return fmt.Errorf("mutation %s not in a state where objections can be filed", mutationID)
	}

	now := time.Now().UTC().Format(time.RFC3339)
	found := false
	for i, a := range mutation.OwnerAlerts {
		if a.AadhaarHash == ownerAadhaarHash {
			mutation.OwnerAlerts[i].Response = "OBJECTED"
			mutation.OwnerAlerts[i].ResponseAt = now
			mutation.OwnerAlerts[i].ObjectionReason = objectionReason
			mutation.OwnerAlerts[i].ObjectionCID = evidenceCID
			found = true
			break
		}
	}
	if !found {
		return fmt.Errorf("aadhaar hash not in owner list for mutation %s", mutationID)
	}

	mutation.Status = MutStatusObjectionFiled
	mutation.UpdatedAt = now

	// Immediately notify District authority + record officer identity
	objectionEvent, _ := json.Marshal(map[string]interface{}{
		"mutationId":      mutationID,
		"dlpiId":          mutation.DLPIId,
		"objectorHash":    ownerAadhaarHash,
		"objectionReason": objectionReason,
		"evidenceCID":     evidenceCID,
		// Officer who initiated is permanently recorded — enables accountability investigation
		"officerName":     mutation.OfficerName,
		"officerHash":     mutation.OfficerHash,
		"officerRank":     mutation.OfficerRank,
		"notifyAuthority": "TEHSILDAR",
	})
	_ = ctx.GetStub().SetEvent("MutationObjectionFiled", objectionEvent)

	return c.saveMutation(ctx, mutation)
}

// RecordPublicNoticeObjection — third party (non-owner) objects during 30-day notice
func (c *MutationManagerContract) RecordPublicNoticeObjection(
	ctx contractapi.TransactionContextInterface,
	mutationID, objectorAadhaarHash, objectionText, evidenceCID string,
) error {
	mutation, err := c.getMutation(ctx, mutationID)
	if err != nil {
		return err
	}
	if mutation.Status != MutStatusPublicNoticePeriod {
		return fmt.Errorf("mutation %s not in public notice period", mutationID)
	}
	if mustParseTime(mutation.PublicNoticeTill).Before(time.Now().UTC()) {
		return fmt.Errorf("public notice period has expired")
	}

	mutation.PublicNoticeObjects++
	mutation.Status = MutStatusCourtReferred
	mutation.UpdatedAt = time.Now().UTC().Format(time.RFC3339)

	event, _ := json.Marshal(map[string]interface{}{
		"mutationId":      mutationID,
		"dlpiId":          mutation.DLPIId,
		"objectorHash":    objectorAadhaarHash,
		"objectionText":   objectionText,
		"evidenceCID":     evidenceCID,
		"totalObjections": mutation.PublicNoticeObjects,
		"officerHash":     mutation.OfficerHash, // officer accountability preserved
	})
	_ = ctx.GetStub().SetEvent("PublicNoticeObjectionFiled", event)
	return c.saveMutation(ctx, mutation)
}

// ExecuteMutation — final step: writes mutation to DLPI chaincode
// For ownership-changing mutations: calls UpdateOwners (multi-owner aware)
// For PARTITION: calls partition function on each affected DLPI
// Endorsement: AND(circle_inspector.member, tehsildar.member)
func (c *MutationManagerContract) ExecuteMutation(
	ctx contractapi.TransactionContextInterface,
	mutationID, finalDocCID string,
) error {
	mutation, err := c.getMutation(ctx, mutationID)
	if err != nil {
		return err
	}

	// Validate execution eligibility
	switch mutation.Status {
	case MutStatusAllConsented, MutStatusPendingExecution:
		// Good to go
	case MutStatusPublicNoticePeriod:
		if mustParseTime(mutation.PublicNoticeTill).After(time.Now().UTC()) {
			return fmt.Errorf("public notice period not complete — expires %s", mutation.PublicNoticeTill)
		}
		if mutation.PublicNoticeObjects > 0 {
			return fmt.Errorf("public notice has %d objection(s) — court referral required", mutation.PublicNoticeObjects)
		}
	default:
		return fmt.Errorf("mutation %s cannot be executed in state: %s", mutationID, mutation.Status)
	}

	now := time.Now().UTC()
	txID := ctx.GetStub().GetTxID()

	if mutation.MutationType == "PARTITION" {
		return c.executePartition(ctx, mutation, now, txID, finalDocCID)
	}

	// For all ownership-changing mutations (except CORRECTION / NAME_UPDATE):
	if mutation.MutationType != "CORRECTION" && mutation.MutationType != "NAME_UPDATE" {
		// Build seller hashes (current owners being removed) and new owner structs
		// For INHERITANCE: sellers = deceased owner (already removed by Uttaradhikar Engine)
		//   so we pass empty sellers — UpdateOwners handles this via succession completion
		// For SALE: handled directly by PropertyTransfer chaincode — this mutation is auto-generated
		// For GIFT/COURT_ORDER: sellers = current owners, new owners from newOwners[]

		sellerHashes := []string{} // for most mutations, removal was handled upstream
		if mutation.MutationType == "GIFT" || mutation.MutationType == "COURT_ORDER" {
			for _, a := range mutation.OwnerAlerts {
				sellerHashes = append(sellerHashes, a.AadhaarHash)
			}
		}

		type CoOwnerInput struct {
			AadhaarHash  string  `json:"aadhaarHash"`
			Name         string  `json:"name"`
			Share        string  `json:"share"`
			ShareDecimal float64 `json:"shareDecimal"`
			IsTribal     bool    `json:"isTribal"`
		}
		newOwnerInputs := make([]CoOwnerInput, len(mutation.NewOwners))
		for i, o := range mutation.NewOwners {
			newOwnerInputs[i] = CoOwnerInput{
				AadhaarHash:  o.AadhaarHash,
				Name:         o.Name,
				Share:        o.Share,
				ShareDecimal: o.ShareDecimal,
				IsTribal:     o.IsTribal,
			}
		}

		sellerHashesJSON, _ := json.Marshal(sellerHashes)
		newOwnersJSON, _ := json.Marshal(newOwnerInputs)
		description := fmt.Sprintf("%s mutation: %d new owner(s)", mutation.MutationType, len(mutation.NewOwners))

		updateArgs := [][]byte{
			[]byte("UpdateOwners"),
			[]byte(mutation.DLPIId),
			sellerHashesJSON,
			newOwnersJSON,
			[]byte(mutation.MutationType),
			[]byte(mutation.OfficerName),
			[]byte(mutation.OfficerHash),
			[]byte(mutation.MutationNo),
			[]byte(finalDocCID),
			[]byte(description),
		}
		if resp := ctx.GetStub().InvokeChaincode("dlpi", updateArgs, ""); resp.Status != 200 {
			return fmt.Errorf("DLPI UpdateOwners failed: %s", resp.Message)
		}
	}

	mutation.Status = MutStatusExecuted
	mutation.ExecutedAt = now.Format(time.RFC3339)
	mutation.UpdatedAt = now.Format(time.RFC3339)
	mutation.SupportingCID = finalDocCID

	if err := c.saveMutation(ctx, mutation); err != nil {
		return err
	}

	event, _ := json.Marshal(map[string]interface{}{
		"mutationId":   mutationID,
		"mutationNo":   mutation.MutationNo,
		"dlpiId":       mutation.DLPIId,
		"mutationType": mutation.MutationType,
		"newOwners":    mutation.NewOwners,
		"officerName":  mutation.OfficerName,
		"officerHash":  mutation.OfficerHash, // accountability: permanent record of who executed
		"executedAt":   mutation.ExecutedAt,
		"txHash":       txID,
	})
	_ = ctx.GetStub().SetEvent("MutationExecuted", event)

	return nil
}

// executePartition — splits one DLPI into N new DLPIs, one per co-owner
// This is the permanent solution to generational ownership fragmentation
func (c *MutationManagerContract) executePartition(
	ctx contractapi.TransactionContextInterface,
	mutation *MutationRequest, now time.Time, txID, finalDocCID string,
) error {
	if mutation.PartitionScheme == nil {
		return fmt.Errorf("PARTITION mutation missing partitionScheme")
	}

	// For each award in the partition scheme, create a new DLPI
	// The new DLPIs are derived from the parent — they inherit tehsil, district, state, land type
	// Only area and boundary change
	for i, award := range mutation.PartitionScheme.Awards {
		newDLPIId := fmt.Sprintf("%s-P%d", mutation.DLPIId, i+1)
		mutation.PartitionScheme.Awards[i].NewDLPIId = newDLPIId

		// Build CreateDLPI input for the new sub-parcel
		// The new DLPI has ONE owner (the award recipient) with share 1/1
		type NewOwnerForCreate struct {
			AadhaarHash  string  `json:"aadhaarHash"`
			Name         string  `json:"name"`
			Share        string  `json:"share"`
			ShareDecimal float64 `json:"shareDecimal"`
			IsVerified   bool    `json:"isVerified"`
			OwnerSince   string  `json:"ownerSince"`
		}
		newOwner := NewOwnerForCreate{
			AadhaarHash:  award.OwnerAadhaarHash,
			Share:        "1/1",
			ShareDecimal: 1.0,
			IsVerified:   true,
			OwnerSince:   now.Format(time.RFC3339),
		}
		newOwnerJSON, _ := json.Marshal([]NewOwnerForCreate{newOwner})

		// Emit event for API layer to call CreateDLPI for each sub-parcel
		partitionEvent, _ := json.Marshal(map[string]interface{}{
			"action":        "CREATE_PARTITION_DLPI",
			"parentDlpiId":  mutation.DLPIId,
			"newDlpiId":     newDLPIId,
			"ownerHash":     award.OwnerAadhaarHash,
			"areaHectares":  award.AreaHectares,
			"shareFraction": award.ShareFraction,
			"newOwners":     string(newOwnerJSON),
			"mutationNo":    mutation.MutationNo,
			"mutationId":    mutation.MutationID,
		})
		_ = ctx.GetStub().SetEvent("PartitionDLPIRequired", partitionEvent)
	}

	// Mark parent DLPI as partitioned (encumbrance = PARTITIONED, no further transfers)
	archiveArgs := [][]byte{
		[]byte("SetEncumbrance"),
		[]byte(mutation.DLPIId),
		[]byte("PARTITIONED"),
		[]byte("Partition completed — see child DLPIs"),
	}
	if resp := ctx.GetStub().InvokeChaincode("dlpi", archiveArgs, ""); resp.Status != 200 {
		return fmt.Errorf("failed to archive parent DLPI: %s", resp.Message)
	}

	mutation.Status = MutStatusExecuted
	mutation.ExecutedAt = now.Format(time.RFC3339)
	mutation.UpdatedAt = now.Format(time.RFC3339)
	return c.saveMutation(ctx, mutation)
}

// GetMutation — retrieve by ID
func (c *MutationManagerContract) GetMutation(
	ctx contractapi.TransactionContextInterface, mutationID string,
) (*MutationRequest, error) {
	return c.getMutation(ctx, mutationID)
}

// QueryPendingMutations — officer dashboard view
func (c *MutationManagerContract) QueryPendingMutations(
	ctx contractapi.TransactionContextInterface,
) ([]*MutationRequest, error) {
	query := `{"selector":{"status":{"$in":["ALERTS_SENT","AWAITING_CONSENTS","ALL_CONSENTED","PENDING_EXECUTION","PUBLIC_NOTICE_PERIOD"]}}}`
	return c.executeQuery(ctx, query)
}

// QueryOfficerMutations — accountability audit: all mutations by a specific officer
func (c *MutationManagerContract) QueryOfficerMutations(
	ctx contractapi.TransactionContextInterface, officerHash string,
) ([]*MutationRequest, error) {
	query := fmt.Sprintf(`{"selector":{"officerAadhaarHash":"%s"}}`, officerHash)
	return c.executeQuery(ctx, query)
}

// QueryMutationsByDLPI — all mutations on a parcel (audit trail)
func (c *MutationManagerContract) QueryMutationsByDLPI(
	ctx contractapi.TransactionContextInterface, dlpiId string,
) ([]*MutationRequest, error) {
	query := fmt.Sprintf(`{"selector":{"dlpiId":"%s"}}`, dlpiId)
	return c.executeQuery(ctx, query)
}

// ─── Internal Helpers ─────────────────────────────────────────────────────────

func (c *MutationManagerContract) allOwnersResponded(m *MutationRequest) bool {
	for _, a := range m.OwnerAlerts {
		if a.Response == "PENDING" {
			return false
		}
	}
	return true
}

func (c *MutationManagerContract) anyObjection(m *MutationRequest) bool {
	for _, a := range m.OwnerAlerts {
		if a.Response == "OBJECTED" {
			return true
		}
	}
	return false
}

func (c *MutationManagerContract) getMutation(ctx contractapi.TransactionContextInterface, id string) (*MutationRequest, error) {
	data, err := ctx.GetStub().GetState(id)
	if err != nil {
		return nil, fmt.Errorf("state read error: %w", err)
	}
	if data == nil {
		return nil, fmt.Errorf("mutation %s not found", id)
	}
	var m MutationRequest
	if err := json.Unmarshal(data, &m); err != nil {
		return nil, fmt.Errorf("unmarshal error: %w", err)
	}
	return &m, nil
}

func (c *MutationManagerContract) saveMutation(ctx contractapi.TransactionContextInterface, m *MutationRequest) error {
	data, err := json.Marshal(m)
	if err != nil {
		return fmt.Errorf("marshal error: %w", err)
	}
	return ctx.GetStub().PutState(m.MutationID, data)
}

func (c *MutationManagerContract) executeQuery(ctx contractapi.TransactionContextInterface, query string) ([]*MutationRequest, error) {
	iter, err := ctx.GetStub().GetQueryResult(query)
	if err != nil {
		return nil, err
	}
	defer iter.Close()
	var results []*MutationRequest
	for iter.HasNext() {
		r, err := iter.Next()
		if err != nil {
			return nil, err
		}
		var m MutationRequest
		if err := json.Unmarshal(r.Value, &m); err != nil {
			return nil, err
		}
		results = append(results, &m)
	}
	return results, nil
}

func mustParseTime(s string) time.Time {
	t, _ := time.Parse(time.RFC3339, s)
	return t
}

func main() {
	cc, err := contractapi.NewChaincode(&MutationManagerContract{})
	if err != nil {
		panic(fmt.Sprintf("Error creating MutationManager chaincode: %v", err))
	}
	if err := cc.Start(); err != nil {
		panic(fmt.Sprintf("Error starting MutationManager chaincode: %v", err))
	}
}
